def bubble_sort(data: list) -> list:
    sorted = False

    while not sorted:
        sorted = True
        for i in range(len(data) - 1):
            if data[i] > data[i+1]:  # switch to < for descending sort
                data[i], data[i+1] = data[i+1], data[i]
