def bubble_sort(arr):
    n = len(arr)

    for i in range(n):
        swapped = False  # Initialize a flag to track whether any swaps were made in this pass

        for j in range(0, n-i-1):
            if arr[j] > arr[j+1]:
                arr[j], arr[j+1] = arr[j+1], arr[j]
                swapped = True  # A swap was made, so set the flag to True

        # If no swaps were made in this pass, the list is already sorted
        if not swapped:
            break

    return(arr)

