def sort(my_list):
    size = len(my_list)

    for i in range(size - 1):
        change = False
        for j in range(size - i - 1):
            if my_list[j] > my_list[j + 1]:
                my_list[j], my_list[j + 1] = my_list[j + 1], my_list[j]
                change = True

        if change is False:
            break

    return my_list

