def bubblesort(thelist):
    for iteration in range(len(thelist) - 1, 0, -1):
        for indice in range(iteration):
            if thelist[indice] > thelist[indice + 1]:
                thelist[indice], thelist[indice + 1] = thelist[indice + 1], thelist[indice]
