def mergeSort ( lst ):
	if not lst:
		return lst
	elif (len(lst) == 1):
		return lst
	else:
		(half1, half2) = split (lst)
		return merge (mergeSort(half1), mergeSort(half2))

def split (L):
	evens = []
	odds = []
	isEven = True
	for e in L:
		if isEven:
			evens.append (e)
		else:
			odds.append (e)
		isEven = not isEven
	return ( evens , odds )

def merge (sorted1, sorted2):
	result = []
	index1 = 0
	index2 = 0
	while index1 < len ( sorted1 ) and index2 < len ( sorted2 ):
		if ( sorted1[index1] <= sorted2[index2]):
			result.append (sorted1[index1])
			index1 = index1 + 1
		else:
			result.append (sorted2[index2])
			index2 = index2 + 1

	if index1 < len ( sorted1 ):
		result.extend ( sorted1 [index1:] )
	elif index2 < len ( sorted2 ):
		result.extend ( sorted2 [index2:] )

	return result

def mergeSort(toSort):
    if len(toSort) <= 1:
    	return toSort

    mIndex = len(toSort) // 2
    left = mergeSort(toSort[:mIndex])
    right = mergeSort(toSort[mIndex:])

    result = []
    while len(left) > 0 and len(right) > 0:
        if left[0] > right[0]:	
            result.append(right.pop(0))
        else:
            result.append(left.pop(0))

    if len(left) > 0:
        result.extend(mergeSort(left))
    else:
        result.extend(mergeSort(right))

    return result

def mergeSort(aOrd):
    if len(aOrd) <= 1:
        return aOrd

    mIndex = len(aOrd) // 2
    izq = mergeSort(aOrd[:mIndex])
    der = mergeSort(aOrd[mIndex:])

    result = []

    while len(izq) > 0 and len(der) > 0:
        if izq[0] > der[0]:
            result.append(der.pop(0))
        else:
            result.append(izq.pop(0))

    if len(izq) > 0:
        result.extend(mergeSort(izq))
    else:
        result.extend(mergeSort(der))

    return result

def merge(left, right):
    i, j = 0, 0
    result = []

    while i < len(left) and j < len(right):

        if left[i] <= right[j]:
            result.append(left[i])
            i += 1
        else:
            result.append(right[j])
            j += 1

    result += left[i:]
    result += right[j:]

    return result


def mergeSort(array):
    if len(array) < 2:
        return array
    mid = len(array) // 2
    left = array[:mid]
    right = array[mid:]
    return merge(mergeSort(left), mergeSort(right))

def merge(left, right, asc=True):

	''' Merge two lists at the end of mergesort. '''

	result = []
	while len(left) > 0 or len(right) > 0:
		if len(left) > 0 and len(right) > 0:
			if left[0] < right[0]:
				result.append(left[0])
				left = left[1:]
			else:
				result.append(right[0])
				right = right[1:]
		elif len(right) > 0:
			result.append(right[0])
			right = right[1:]
		elif len(left) > 0:
			result.append(left[0])
			left = left[1:]
	return result


