def merge(lista, listb):
    pa = 0
    pb = 0
    result = []
    while True:
        if lista[pa] <= listb[pb]:
            result.append(lista[pa])
            pa += 1
            if pa >= len(lista):
                result += listb[pb:]
                break
        else:
            result.append(listb[pb])
            pb += 1
            if pb >= len(listb):
                result += lista[pa:]
                break

    return result


def mergesort(_list):
    '''Takes _list and returns a sorted version of it, using mergesort'''
    if len(_list) <= 1:
        return _list

    middle = int(len(_list) / 2)
    left = _list[:middle]
    right = _list[middle:]
    return merge(mergesort(left), mergesort(right))

def mergesort(lst):
    def merge(l1, l2):
        if not l1:
            return l2
        if not l2:
            return l1
        return ([l1[0]] + merge(l1[1:], l2)
                if l1[0] < l2[0]
                else [l2[0]] + merge(l1, l2[1:]))
    length = len(lst)
    if length < 2:
        return lst
    return merge(
        mergesort(lst[:length//2]),
        mergesort(lst[length//2:]))

def mergesort(x):
    copy = list(x)

    return(mergesort_set(copy, x, 0, len(x)))





def mergesort_set(x, final_set, start, finish):

    if finish - start < 2: 
        return
    if finish - start == 2:
        if final_set[start] > final_set[start + 1]:
            final_set[start], final_set[start + 1] = final_set[start + 1],  final_set[start] # simple swap
        return

    mid = (start + finish)//2 # floor division
    mergesort_set(final_set, x,  start, mid)
    mergesort_set(final_set, x, mid, finish)

    i = start
    j = mid
    index = start
    while index < finish:
        if j >= finish or (i < mid and x[i] < x[j]):
            final_set[index] =x[i]
            i += 1
        else:
            final_set[index] = x[j]
            j += 1

        index += 1
    return(final_set)

def merge(left, right):
    res = []
    while left != [] and right != []:
        if left[0] < right[0]:
            res.append(left.pop(0))
        else:
            res.append(right.pop(0))
    res.extend(left)
    res.extend(right)
    return res

def mergesort(list):
    if len(list) == 1:
        return list
    left = mergesort(list[0:len(list)//2])
    right = mergesort(list[len(list)//2:len(list)])
    return merge(left, right)

def mergesort(A):
  def _merge(A, left, m, right):
    left_A, right_A = A[left:m], A[m:right]
    left_len, right_len = len(left_A), len(right_A)

    l_i, r_i, k = 0, 0, left
    while l_i < left_len and r_i < right_len:
      if left_A[l_i] <= right_A[r_i]:
        A[k] = left_A[l_i]
        l_i += 1
        k += 1
      else:
        A[k] = right_A[r_i]
        r_i += 1
        k += 1

    while l_i < left_len:
      A[k] = left_A[l_i]
      l_i += 1
      k += 1
    while r_i < right_len:
      A[k] = right_A[r_i]
      r_i += 1
      k += 1



  def _mergesort(A, left, right):
    if left < right:
      m = (left + right)//2
      _mergesort(A, m+1, right)
      _mergesort(A, left, m)
      _merge(A, left, m+1, right+1)

    return(A)
  return(_mergesort(A, 0, len(A)))

def merge(arr, l, m, r):
    n1 = m - l + 1
    n2 = r - m

    L = [0] * (n1)
    R = [0] * (n2)

    for i in range(0, n1):
        L[i] = arr[l + i]

    for j in range(0, n2):
        R[j] = arr[m + 1 + j]
    i = 0     
    j = 0     
    k = l     

    while i < n1 and j < n2:
        if L[i] <= R[j]:
            arr[k] = L[i]
            i += 1
        else:
            arr[k] = R[j]
            j += 1
        k += 1

    while i < n1:
        arr[k] = L[i]
        i += 1
        k += 1

    while j < n2:
        arr[k] = R[j]
        j += 1
        k += 1


def mergeSort(arr, l, r):
    if l < r:

        m = l+(r-l)//2

        mergeSort(arr, l, m)
        mergeSort(arr, m+1, r)
        merge(arr, l, m, r)
    return(arr)

def algorithm(arr):
    return(mergeSort(arr,0,len(arr)-1))

def mergesort(list_of_numbers):
    """ Return the sorted list using mergesort"""
    # type: (list[int]) -> list[int]
    if len(list_of_numbers) < 2:
        return list_of_numbers
    else:
        middle = int(len(list_of_numbers)/2)
        left_half = list_of_numbers[0:middle]
        right_half = list_of_numbers[middle:]
        accumulator = []
        return merge(mergesort(left_half),
                     mergesort(right_half),
                     accumulator)


def merge(left, right, accumulator):
    """Merge left, right, and accumulator lists in an ordered way"""
    # type: (list[int], list[int], list[int]) -> list[int]
    if len(left) == 0 and len(right) == 0:
        return accumulator
    elif len(left) == 0:
        return accumulator + right
    elif len(right) == 0:
        return accumulator + left
    elif left[0] < right[0]:
        return merge(left[1:], right,
                     accumulator + [left[0]])
    elif right[0] <= left[0]:
        return merge(left, right[1:],
                     accumulator + [right[0]])

import math

#merger Function that merges two sorted arrays into 1 sorted array
def merger(arr1, arr2):
    i = 0
    j = 0
    mergedArr = []

    a = len(arr1)
    b = len(arr2)

    while i < a and j < b:
        if arr1[i] > arr2[j]:
            mergedArr.append(arr2[j])
            j = j + 1
        else:
            mergedArr.append(arr1[i])
            i = i + 1
    while i < a:
        mergedArr.append(arr1[i])
        i = i + 1
    while j < b:
        mergedArr.append(arr2[j])
        j = j + 1
    return(mergedArr)

def mergeSort(arr):
    #array of length 1 is already sorted
    if len(arr) == 1:
        return arr

    #split the array down the middle into two arrays repeatedly using recursion
    middle = math.floor(len(arr)/2)
    left = mergeSort(arr[0: int(middle)])
    right = mergeSort(arr[int(middle):])

    #return the merged and sorted array
    return(merger(left, right))

def mergesort(L):
	return L if len(L) < 2 else merge(mergesort(L[:len(L)//2]), mergesort(L[len(L)//2:]))

def merge(A,B):
	Out = []
	iA = iB = 0
	while len(A)+len(B) > iA + iB:
		if len(B) <= iB or (len(A) > iA and A[iA] < B[iB]):
			Out.append(A[iA])
			iA = iA + 1
		else:
			Out.append(B[iB])
			iB = iB + 1
	return Out

def merge(left, right, arr):
    l_itr = 0
    r_itr = 0
    arr_itr = 0
    while(l_itr < len(left) or r_itr < len(right)):
        if l_itr < len(left): l_val = left[l_itr]
        else: l_val = float('inf')
        if r_itr < len(right): r_val = right[r_itr]
        else: r_val = float('inf')
        if l_val <= r_val:
            arr[arr_itr] = l_val
            l_itr += 1
        else:
            arr[arr_itr] = r_val
            r_itr += 1
        arr_itr += 1
def mergeSort(arr):
    if len(arr) == 1 or len(arr) == 0: return
    mid = len(arr)//2
    left = arr[:mid]
    right = arr[mid:]
    mergeSort(left)
    mergeSort(right)
    merge(left, right, arr)
    return(arr)

