    while len(A):
        build_max_heap(A)
        ret.append(A[0])
        A = A[1:]
    return list(reversed(ret))

def heapify(arr, i):
    # O(lgn)
    left_idx = 2*i+1
    if left_idx >= len(arr):
        return
    right_idx = left_idx + 1
    if right_idx >= len(arr):
        left = arr[left_idx]
        if left > arr[i]:
            arr[i], arr[left_idx] = arr[left_idx], arr[i]
    else:
        left = arr[left_idx]
        right = arr[right_idx]
        cur = arr[i]

        if left > right:
            m = left
            m_idx = left_idx
        else:
            m = right 
            m_idx = right_idx

        if cur < m:
            arr[i], arr[m_idx] = arr[m_idx], arr[i]
            heapify(arr, m_idx)


