        s.append(arr[-1])
        del arr[-1]
        heapify(arr, 0)
    return list(reversed(s))

def heap_sort(arr):
    '''
    Heap Sort
    Complexity: O(n log(n))
    '''
    end = len(arr) - 1
    while end > 0:
        arr = heap_tree(arr, end + 1)
        arr[0], arr[end] = arr[end], arr[0]
        end -= 1
    return arr


def heap_tree(arr, end):
    # Make a heap tree
    for x in range(1, end):
        pos = x
        while True:
            parent = pos // 2 if pos != 2 and pos % 2 == 0 else pos // 2 - 1
            if parent < 0:
                parent = 0
            if parent >= 0 and arr[pos] > arr[parent]:
                arr[pos], arr[parent] = arr[parent], arr[pos]
                pos = parent
            else:
                break
    return arr

def heapsort(lists):
    def heapify(lists):
        start=(len(lists)-2)//2
        while start>=0:
            siftDown(lists,start,len(lists)-1)
            start-=1

    def siftDown(lists, start, end):
        root = start
        while root*2+1<=end:
            child = root * 2 + 1
            if child + 1 <= end and lists[child] < lists[child + 1]:
                child += 1
            if child <= end and lists[root] < lists[child]:
                lists[root], lists[child] = lists[child], lists[root]
                root = child
            else:
                return

    heapify(lists)
    end = len(lists) - 1
    while end > 0:
        lists[end], lists[0] = lists[0], lists[end]
        siftDown(lists, 0, end - 1)
        end -= 1

    return(lists)

def sift_down(lst, top, end):
    pos = end
    newitem = lst[pos]
    while pos > top:
        parentpos = (pos - 1) >> 1
        parent = lst[parentpos]
        if newitem < parent:
            lst[pos] = parent
            pos = parentpos
            continue
        else:
            break
    lst[pos] = newitem


def sift_up(lst, top):
    pos, end = top, len(lst)
    newitem = lst[pos]
    childpos = (pos << 1) + 1
    while childpos < end:
        rightpos = childpos + 1
        if rightpos < end and lst[rightpos] < lst[childpos]:
            childpos = rightpos
        lst[pos] = lst[childpos]
        pos = childpos
        childpos = (pos << 1) + 1
    lst[pos] = newitem
    sift_down(lst, top, pos)


def heapify(lst):
    for i in reversed(range(len(lst) >> 1)):
        sift_up(lst, i)


def heap_pop(lst):
    lastitem = lst.pop()
    if lst:
        returnitem = lst[0]
        lst[0] = lastitem
        sift_up(lst, 0)
        return returnitem
    return lastitem


