def stone_down(h, i):
    n = len(h)
    if i < n:
        c = i
        l = 2*i + 1
        r = 2*i + 2
        if l < n and h[c] > h[l]:
            c = l
        if r < n and h[c] > h[r]:
            c = r
        if c != i:
            h[c], h[i] = h[i], h[c]
            stone_down(h, c)

def heapify(h):  # O(n)
    n = len(h)-1
    n = (n-1)//2
    for i in reversed(range(n+1)):
        stone_down(h, i)
    return h

def bubble_up(h, i):
    p = (i-1)//2
    if h[i] < h[p]:
        h[i], h[p] = h[p], h[i]
        bubble_up(h, p)

def heappush(h, v):  # O(logn)
    h.append(v)
    bubble_up(h, len(h)-1)

def heappop(h):    # O(logn)
    res = h[0]
    h[0] = h[-1]
    h.pop()
    stone_down(h, 0)
    return res

def heapify(arr, n, i):
  # initialize largest as the root
  largest = i
  left_node = 2*i +1
  right_node = 2*i+2

  if left_node < n and arr[i] < arr[left_node]:
    largest = left_node

  if right_node < n and arr[largest] < arr[right_node]:
    largest = right_node

  # swap the root
  if largest != i:
    arr[i], arr[largest] = arr[largest], arr[i]

    # Run heapify recursively
    heapify(arr, n, largest)

