def Desloca_baixo(lista, inicio, fim):
    max = 2 * inicio + 1
    while (max <= fim):

        if (max < fim) and (lista[max] < lista[max + 1]):
            max += 1

        if lista[max] > lista[inicio]:
            lista[inicio], lista[max] = lista[max], lista[inicio]
            inicio = max
            max = 2 * inicio + 1

        else:
            return

