def heap_sort(alist):
    """function: heap sort
        loop step: 1.change the position of fist and last which is the max one of the heap
                   2.take the heap.size-1 element of heap to max heapify
                   3.go to step 1 until heap.size < 2"""
    build_max_heap(alist)
    length = len(alist)
    for i in range(length - 1, 0, -1):
        alist[i], alist[0] = alist[0], alist[i]
