def max_heapify(clist, end, t):
    """function: make clist[t-1:] a max heap
        assume the left and the right children of t are both max heaps
        note: this method of passing argument to overcome the lack of pointer in Python """
    if 2 * t <= end and clist[2 * t - 1] > clist[t - 1]:
        largest = 2 * t
    else:
        largest = t
    if 2 * t + 1 <= end and clist[2 * t] > clist[largest - 1]:
        largest = 2 * t + 1
    if t != largest:
        clist[t - 1], clist[largest - 1] = clist[largest - 1], clist[t - 1]
        return max_heapify(clist, end, largest)
    else:
        return clist

def heapify(lst, start, end):
    father = start
    child = father * 2 + 1

    while child <= end:
        if child + 1 <= end and lst[child] < lst[child + 1]:
            child += 1

        if lst[father] >= lst[child]:
            break
        else:
            lst[father], lst[child] = lst[child], lst[father]
            father = child
            child = father * 2 + 1


