# establish heap property (used by create_heap)
def establish_heap_property(list2, first, last):
    while 2 * first + 1 <= last:
        k = 2 * first + 1
        if k < last and list2[k] < list2[k + 1]:
            k += 1
        if list2[first] >= list2[k]:
            break
        list2[first], list2[k] = list2[k], list2[first]  # swap
        first = k

# create heap (used by heap_sort)
def create_heap(list2, first, last):
    i = last//2
    while i >= first:
        establish_heap_property(list2, i, last)
        i -= 1

def heap_sort(list2):
    first = 0
    last = len(list2) - 1
    create_heap(list2, first, last)
    for i in range(last, first, -1):
        list2[i], list2[first] = list2[first], list2[i]  # swap
        establish_heap_property(list2, first, i - 1)
    return(list2)

def heap_sort(lst):
    def heapify():
        for start in range(((len(lst) - 1) // 2), -1, -1):
            shift_down(start, len(lst) - 1)

    def shift_down(start, end):
        if start * 2 + 1 > end:
            return

        left_index = start * 2 + 1
        right_index = start * 2 + 2

        parent = lst[start]
        left = lst[left_index]
        right = lst[right_index] if right_index <= end else left - 1

        if parent < max(left, right):
            if left > right:
                lst[start], lst[left_index] = lst[left_index], lst[start]
                shift_down(left_index, end)
            else:
                lst[start], lst[right_index] = lst[right_index], lst[start]
                shift_down(right_index, end)

    heapify()

    for end in range(len(lst) - 1, 0, -1):
        lst[0], lst[end] = lst[end], lst[0]
        shift_down(0, end - 1)

    return lst

