        h.pop()
        siftdown(h, 1)
        return t


def siftup(h, i):
    while i >= 2:
        j = i // 2
        if h[j] <= h[i]:
            return
        swap(h, i, j)
        i = j


def siftdown(h, i):
    while i*2 < len(h):
        l = i*2
        r = l+1
        j = l if r >= len(h) or h[l] <= h[r] else r
        if h[i] <= h[j]:
            break
        swap(h, i, j)
        i = j


def siftdownn(h, i, n):
    # slightly modified version of siftdown
    # siftdown element of index i to at max index n-1
    while i*2 < n:
        l = i*2
        r = l+1
        j = l if r >= n or h[l] <= h[r] else r
        if h[i] <= h[j]:
            break
        swap(h, i, j)
        i = j


