def max_heapify(clist, end, t):
	"""function: make clist[t-1:] a max heap ; end is the length of clist
		assume the left and the right children of t are both max heaps
		note: this method of passing argument to overcome the lack of pointer in Python """
	if 2 * t <= end and clist[2 * t - 1] > clist[t - 1]:
		largest = 2 * t
	else:
		largest = t
	if 2 * t + 1 <= end and clist[2 * t] > clist[largest - 1]:
		largest = 2 * t + 1
	if t != largest:
		clist[t - 1], clist[largest - 1] = clist[largest - 1], clist[t - 1]
		return max_heapify(clist, end, largest)
	else:
		return clist

def heap_sort(a_list):
    heap_size = len(a_list)

    def parent(i):
        return int((i - 1) / 2)

    def left(i):
        return 2 * i + 1

    def right(i):
        return 2 * i + 2

    def max_heapify(i):
        l = left(i)
        r = right(i)
        if l < heap_size and a_list[l] > a_list[i]:
            largest = l
        else:
            largest = i
        if r < heap_size and a_list[r] > a_list[largest]:
            largest = r
        if not largest == i:
            a_list[largest], a_list[i] = a_list[i], a_list[largest]
            max_heapify(largest)

    def build_max_heap():
        for i in range(int((len(a_list) - 1) / 2), -1, -1):
            max_heapify(i)

    build_max_heap()
    for i in range(len(a_list) - 1, 0, -1):
        a_list[0], a_list[i] = a_list[i], a_list[0]
        heap_size -= 1
        max_heapify(0)
    return(a_list)

def heapify(arr, n, i):
    largest = i
    left = 2 * i + 1
    right = 2 * i + 2

    if left < n and arr[i] < arr[left]:
        largest = left

    if right < n and arr[largest] < arr[right]:
        largest = right

    if largest != i:
        (arr[i], arr[largest]) = (arr[largest], arr[i])
        heapify(arr, n, largest)

def heapSort(arr):
    n = len(arr)

    for i in range(n // 2 - 1, -1, -1):
        heapify(arr, n, i)

    for i in range(n - 1, 0, -1):
        (arr[i], arr[0]) = (arr[0], arr[i])
        heapify(arr, i, 0)
    return(arr)

def heapify(data, index, heap_size):
    i_max = index
    i_left = 2 * index + 1
    i_right = 2 * index + 2

    if i_left < heap_size and data[i_left] > data[index]:
        i_max = i_left
    if i_right < heap_size and data[i_right] > data[i_max]:
        i_max = i_right
    if i_max != index:
        data[i_max], data[index] = data[index], data[i_max]
        heapify(data, i_max, heap_size)

def build_heap(data):
    heap_size = len(data)
    parent = heap_size // 2
    for i in range(parent-1, -1, -1):
        heapify(data, i, heap_size)

def heap_sort(data):
    if data:
        heap_size = len(data)

        build_heap(data)

        for i in range(heap_size - 1, 0, -1):
            data[0], data[i] = data[i], data[0]
            heapify(data, 0, i)

    return(data)

def heapify(data, n, i):
    largest = i
    l = 2 * i + 1
    r = 2 * i + 2

    # Compare left child and root
    if l < n and data[i] < data[l]:
        largest = l

    # Compare right child and root
    if r < n and data[largest] < data[r]:
        largest = r

    # Change root, if needed
    if largest != i:
        data[i],data[largest] = data[largest],data[i]

        # Heapify the root
        heapify(data, n, largest)

# The main function to sort an data array of given size
def heapSort(data):
    n = len(data)

    # Build a maxheap
    for i in range(n, -1, -1):
        heapify(data, n, i)

    # One by one extract elements
    for i in range(n-1, 0, -1):
        data[i], data[0] = data[0], data[i]
        heapify(data, i, 0)
    return(data)

def HeapSort(A):
    def heapify(A):
        start = (len(A) - 2) // 2
        while start >= 0:
            siftDown(A, start, len(A) - 1)
            start -= 1

    def siftDown(A, start, end):
        root = start
        while root * 2 + 1 <= end:
            child = root * 2 + 1
            if child + 1 <= end and A[child] < A[child + 1]:
                child += 1
            if child <= end and A[root] < A[child]:
                A[root], A[child] = A[child], A[root]
                root = child
            else:
                return

    heapify(A)
    end = len(A) - 1
    while end > 0:
        A[end], A[0] = A[0], A[end]
        siftDown(A, 0, end - 1)
        end -= 1
    return(A)

import random


def build_max_heap(data):
    pos = len(data)//2 - 1
    for i in range(pos, -1, -1):
        down_shift(data, i, len(data)-1)


def down_shift(data, pos, limit):
	left = (pos + 1) * 2 -1
	right = left + 1
	if left > limit:
		return 
	if right > limit:
		if(data[pos]< data[left]):
			data[pos], data[left] = data[left], data[pos]
		return 

	tmp = max(data[left], data[right])
	if data[pos] < tmp:
		if(data[left]> data[right]):
			data[pos], data[left] = data[left], data[pos]
			down_shift(data, left, limit)
		else:
			data[pos], data[right] = data[right], data[pos]
			down_shift(data, right, limit)


def heap_sort(data):
    build_max_heap(data)
    pos = len(data)-1
    k = 1
    for i in range(pos, 0, -1 ):
        data[i], data[0] = data[0], data[i]
        down_shift(data, 0, len(data)-1-k)
        k = k + 1
    return(data)

def sift_down(arr, i):
    if 2 * i + 1 < len(arr):
        if 2 * i + 2 < len(arr):
            max_n = max(arr[2*i+1], arr[2*i+2], arr[i])
            if max_n == arr[i]:
                return
            elif max_n == arr[2*i+1]:
                arr[i], arr[2*i+1] = arr[2*i+1], arr[i]
                sift_down(arr, 2*i+1)
            elif max_n == arr[2*i+2]:
                arr[i], arr[2*i+2] = arr[2*i+2], arr[i]
                sift_down(arr, 2*i+2)
        else:
            if arr[i] >= arr[2*i+1]:
                return
            else:
                arr[i], arr[2*i+1] = arr[2*i+1], arr[i]
                sift_down(arr, 2*i+1)
    else:
        return

def heapify(arr):
    i = 0
    while 2*i+1 < len(arr):
        i = 2 * i + 1

    for j in range(i, -1, -1):
        sift_down(arr, j)


def heap_sort(arr):
    heapify(arr)

    res = []
    tmp = len(arr)
    for _ in range(tmp):
        res = [arr[0]] + res
        arr[0], arr[-1] = arr[-1], arr[0]
        arr = arr[:-1]
        sift_down(arr, 0)

    return res

import operator


def swap(l: list, i: int, j: int):
    assert i < len(l), i
    assert j < len(l), j
    l[i], l[j] = l[j], l[i]


def heap_sort(l: list) -> list:
    if len(l) in (0, 1):
        return l
    # Invariant: heap[parent] >= heap[*children]
    heap = [None]
    ROOT = 1

    def parent(idx: int) -> int:
        assert idx > 0
        return None if idx == 1 else idx // 2

    def children(idx: int) -> tuple[int, int]:
        a = idx * 2
        l = len(heap)
        return (a if a < l else None, a + 1 if a + 1 < l else None)

    def swim(idx):
        val = heap[idx]
        parent_idx = parent(idx)
        if parent_idx is None:
            return
        if val > heap[parent_idx]:
            swap(heap, parent_idx, idx)
            swim(parent_idx)
        a, b = children(idx)
        assert a is None or heap[idx] >= heap[a]
        assert b is None or heap[idx] >= heap[b]

    def sink(idx):
        a, b = children(idx)
        if a is None and b is None:
            return
        target_val = heap[idx]
        larger_children = []
        if a is not None and heap[a] > target_val:
            larger_children.append((a, heap[a]))
        if b is not None and heap[b] > target_val:
            larger_children.append((b, heap[b]))
        if not larger_children:
            return  # we are done
        largest_child = max(larger_children, key=operator.itemgetter(1))[0]
        swap(heap, largest_child, idx)
        sink(largest_child)
        # check heap invariants
        assert a is None or heap[idx] >= heap[a]
        assert b is None or heap[idx] >= heap[b]

    def insert(val):
        idx = len(heap)
        heap.append(val)
        swim(idx)

    def removeLargest():
        assert len(heap) > 1
        largest = heap[ROOT]
        new_root = heap.pop()
        try:
            heap[ROOT] = new_root
        except IndexError:
            # we are now empty (nothing boot heap[0])
            pass
        else:
            sink(ROOT)
        return largest

    for value in l:
        insert(value)

    res = []
    while len(heap) > 1:
        res.append(removeLargest())
    res.reverse()
    return res

def heapSort(listToSort):
  for start in range((len(listToSort)-2)//2, -1, -1):
    siftdown(listToSort, start, len(listToSort)-1)

  for end in range(len(listToSort)-1, 0, -1):
    listToSort[end], listToSort[0] = listToSort[0], listToSort[end]
    siftdown(listToSort, 0, end - 1)
  return listToSort

# repair the heap whose root element is at index 'start', assuming the heaps rooted at its children are valid
def siftdown(listToSort, start, end):
  root = start
  while True:
    child = root * 2 + 1
    if child > end: break
    if child + 1 <= end and listToSort[child] < listToSort[child + 1]:
      child += 1
    if listToSort[root] < listToSort[child]:
      listToSort[root], listToSort[child] = listToSort[child], listToSort[root]
      root = child
    else:
      break

def heapify(arr, n, i):
      # Знайходимо найбільше серед кореня та гілок
      largest = i
      l = 2 * i + 1
      r = 2 * i + 2

      if l < n and arr[i] < arr[l]:
          largest = l

      if r < n and arr[largest] < arr[r]:
          largest = r

      # Якщо корінь не найбільший, поміняємо місцями з найбільшим і продовжуємо об’єднання
      if largest != i:
          arr[i], arr[largest] = arr[largest], arr[i]
          heapify(arr, n, largest)


def heapSort(arr):
      n = len(arr)

      # Будуємо максимальну 'купу'
      for i in range(n//2, -1, -1):
          heapify(arr, n, i)

      for i in range(n-1, 0, -1):
          # Міняємо
          arr[i], arr[0] = arr[0], arr[i]

          # Сортуємо короневий елемент
          heapify(arr, i, 0)
      return(arr)

def quicksort(data, lo=0, hi=None):
    if hi is None: hi = len(data) - 1
    pivot = data[lo]
    i, j = lo, hi

    while i <= j:
        while data[i] < pivot:
            i += 1
        while data[j] > pivot:
            j -= 1

        if i <= j:
            data[i], data[j] = data[j], data[i]
            i += 1
            j -= 1

    if j > lo:
        quicksort(data, lo, j)
    if i < hi:
        quicksort(data, i, hi)

    return(data)

def partition(arr, low, high):
    i = low - 1
    pivot = arr[high]

    for j in range(low, high):
        if arr[j] <= pivot:
            i = i + 1
            arr[i], arr[j] = arr[j], arr[i]

    arr[i + 1], arr[high] = arr[high], arr[i + 1]
    return i + 1

