def quicksort(data, left=0, right=None):
    if right is None: right = len(data)-1
    if left >= right:
        return

    i = left
    swap(data, left, i)
    pivot = data[left]

    i, j, k = left, right, left + 1

    while k <= j:
        if data[k] < pivot:
            swap(data, i, k)
            i += 1
        elif data[k] > pivot:
            swap(data, j, k)
            j -= 1
            k -= 1
        k += 1

    quicksort(data, left, i - 1)
    quicksort(data, j + 1, right)
    return(data)

def quicksort(nums,first=0,end=None):
  if end is None: end = len(nums)-1
  if first >= end: 
    return(nums)

  mid_value = nums[first]
  left_pointer = first
  right_pointer = end

  while left_pointer < right_pointer:
    while left_pointer < right_pointer and nums[right_pointer] >= mid_value:
      right_pointer -= 1

    nums[left_pointer] = nums[right_pointer]

    while left_pointer < right_pointer and nums[left_pointer] < mid_value:
      left_pointer += 1
    nums[right_pointer] = nums[left_pointer]

  nums[left_pointer] = mid_value

  quicksort(nums,first,left_pointer-1)
  quicksort(nums,left_pointer+1,end)
  return(nums)

