        return quicksort(less)+[temp]+quicksort(right)

def partition(seq, first, last):
    pivot = seq[first]
    left = first + 1
    right = last

    while True:
        # Move left while we're in bounds and element is less than pivot
        while left <= right and seq[left] < pivot:
            left += 1
        # Move right while we're in bounds and element is greater than pivot
        while right >= first and seq[right] > pivot:
            right -= 1
        # If pointers cross, we're done
        if left > right:
            break
        # Otherwise, swap elements
        seq[left], seq[right] = seq[right], seq[left]
        left += 1
        right -= 1

    # Put pivot in its final place
    seq[first], seq[right] = seq[right], seq[first]
    return right

def quicksort(seq, first=0, last=None):
