        return

    pos = partition(seq, first, last)
    quicksort(seq, first, pos - 1)
    quicksort(seq, pos + 1, last)
    return(seq)

def quicksort(a, pivot_idx=0, median=False):
    if len(a) <= 1:
        return a
    else:
        if median is True:
            if (len(a) % 2 == 0):
                idx = len(a) / 2
            else:
                idx = (len(a) // 2) + 1
            idx = int(idx)
            mid_ele = a[idx]
            first_ele = a[0]
            last_ele = a[-1]
            temp_a = [first_ele, mid_ele, last_ele]
            temp_b = [0, idx, -1]
            temp_c = sorted(set(temp_a))
            pivot_idx = temp_b[temp_a.index(temp_c[1])]

        p = partition(a, pivot_idx);
        a = p[0]
        pivot = p[1]
        a[:pivot] = quicksort(a[:pivot], pivot_idx, median)
        a[pivot+1:] = quicksort(a[pivot+1:], pivot_idx, median)
    return a

def partition(a, pivot_idx):
    temp = a[0]
    a[0] = a[pivot_idx]
    a[pivot_idx] = temp
    pivot_element = a[0]

    partition_point = 1
    for seen_array in range(1,len(a)):
        if (a[seen_array] < pivot_element):
            temp = a[partition_point]
            a[partition_point] = a[seen_array]
            a[seen_array] = temp
            partition_point+=1;
        else:
            pass
    temp = a[partition_point-1]
    a[partition_point-1] = pivot_element
    a[0] = temp
    return (a, partition_point-1)

def partition(a, p, r):
    i = p
    j = r
    m = a[i]
    while True:
        while a[j] > m and i < j:
            j -= 1
        if i < j:
            a[i], a[j] = a[j], a[i]
            i += 1
        while a[i] < m and i < j:
            i += 1
        if i < j:
            a[i], a[j] = a[j], a[i]
            j -= 1
        if i == j:
            break
    return i

