  swap(a,p,g)
  return g

def quicksort(a,s=0,e=None):
  if e is None: e=len(a)-1
  if s >= e:
    return
  p = partition(a,s,e)
  quicksort(a,s,p-1)
  quicksort(a,p+1,e)
  return(a)

def quicksort(arr):
    if len(arr) < 1:
        return arr
    pivot = arr[len(arr)//2]
    left = [x for x in arr if x < pivot]
    middle = [x for x in arr if x==pivot]
    right =[x for x in arr if x > pivot]
    return quicksort(left) + middle + quicksort(right)

def partition(arr, start, end):
    pivot = start
    for i in range(start + 1, end):
        if (arr[i] < arr[pivot]):
            temp = arr[i]
            arr[i] = arr[pivot + 1]
            arr[pivot + 1] = arr[pivot]
            arr[pivot] = temp
    return pivot

def quicksort(arr, start=0, end=None):
