def partition(start, end, array):
  pivot_index = start
  pivot = array[pivot_index]

  while start < end:
    while start < len(array) and array[start] <= pivot:
      start += 1
    while array[end] > pivot:
      end -= 1
    if(start < end):
      array[start], array[end] = array[end], array[start]

  array[end], array[pivot_index] = array[pivot_index], array[end]
  return end

def quicksort(array, start=0, end=None):
  if end is None: end=len(array)-1
  if (start < end):
    p = partition(start, end, array)
    quicksort(array, start, p - 1)
    quicksort(array, p + 1, end)
    return(array)

def quicksort(A):
    def partition(l,r):
        if l<r:
            p = A[(l+r) >> 1]
            lp = l
            rp = r
            while lp < rp:
                while A[lp] < p:
                    lp+=1
                while A[rp] > p:
                    rp-=1
                if lp <= rp:
                    A[lp], A[rp] = A[rp], A[lp]
                    lp+=1
                    rp-=1
            partition(l,rp)
            partition(lp,r)

    partition(0, len(A) - 1)
    return A

import math
def jump_search(alist, val):

	length = len(alist)

	# Calculating jump
	jump = int(math.sqrt(length))

	left, right = 0, 0

	while left < length and alist[left] <= val:
		right = min(length - 1, left + jump)

		if alist[left] <= val and alist[right] >= val:
			break

		left += jump;

	if left >= length or alist[left] > val:
		return -1

	right = min(length - 1, right)

	i = left
	while i <= right and alist[i] <= val:
		if alist[i] == val:
			return i
		i += 1

	return -1

import math

def jump_search(array, key):
    size = len(array)
    block_size = math.sqrt(size)

    index = 0
    while array[math.trunc(min(block_size, size) - 1)] < key:
        index = block_size
        block_size += math.sqrt(size)

        if index >= size:
            return -1

    while array[math.trunc(index)] < key:
        index += 1

        if index == min(block_size, size):
            return -1

    if array[int(index)] == key:
        return math.trunc(index)

    return -1

def bubble_sort_asc(data):
    updated = False

    while True:
        for i in range(len(data) - 1):
            if data[i] > data[i + 1]:
                data[i], data[i + 1] = data[i + 1], data[i]

                if not updated:
                    updated = True
        if not updated:
            break 
        updated = False

    return(data)

# Jump Search Function
def jumpSearch(arr, x):
  n = len(arr)
  step = int(n**0.5)
  prev = next = 0
  for i in range(0, n, step):
    if arr[i] == x:
      return i
    elif arr[i] < x:
      prev = i
    elif arr[i] > x:
      next = i
      break
  for k in range(prev, next + 1):
    if arr[k] == x:
      return k
  return -1

