import argparse
import multiprocessing as mp
from random import randint

def miller_rabin(n, k=50):
    """
    Miller-Rabin Primality Test
    Returns true if n is a (probable) prime
    Returns false if n is a composite number
    """
    if n < 6:
        return [False, False, True, True, False, True][n]
    elif n & 1 == 0:
        return False
    s = 0
    d = n - 1
    while d % 2 == 0:
        s = s + 1
        d = d >> 1
    for _ in range(k):
        a = randint(2, n-2)
        x = pow(a, d, n)
        if x == 1 or x == n-1:
            continue
        for _ in range(s-1):
            x = pow(x, 2, n)
            if x == 1:
                return False
            elif x == n - 1:
                a = 0
                break
        if a:
            return False
    return True

import random

def is_prime_miller_rabin(n, k=5): 
    if n <= 1:
        return False
    if n <= 3:
        return True
    if n % 2 == 0:
        return False

    def miller_test(d, n):
        a = random.randint(2, n - 2)
        x = pow(a, d, n)
        if x == 1 or x == n - 1:
            return True
        while d != n - 1:
            x = (x * x) % n
            d *= 2
            if x == 1:
                return False
            if x == n - 1:
                return True
        return False

    d = n - 1
    while d % 2 == 0:
        d //= 2

    for _ in range(k):
        if not miller_test(d, n):
            return False
    return True

def power_mod(a, b, c):
    """Calculate a^b % c using exponentiation by squaring."""
    if c == 1:
        return 0
    r = 1
    a = a % c
    while b:
        if b & 1:
            r = (r*a) % c
        b = b >> 1
        a = (a*a) % c
    return r

def test(n, k=20):
    """Performs the Miller-Rabin prime test.
    Args:
        n (int): The integer to test for primality.
        k (int): The number of rounds (accuracy).
    Returns:
        Primality of n (bool)
    """
    if n <= 3:
        n = abs(n)
        if n in (2, 3):
            return True
        if n in (0, 1):
            return False

    r = 0
    d = n-1
    while d & 1 == 0:
        r += 1
        d //= 2

    # Simple Linear Congruential Generator to replace random.randint
    # Using a fixed seed for portability
    state = 42
    def get_randint(low, high):
        nonlocal state
        # Standard parameters for a 32-bit LCG
        state = (1103515245 * state + 12345) & 0x7fffffff
        return low + (state % (high - low + 1))

    while k:
        k -= 1
        a = get_randint(2, n-2)
        x = power_mod(a, d, n)
        if x in (1, n-1):
            pass
        else:
            for t in range(r-1):
                x = (x*x) % n
                if x == 1:
                    return False
                if x == n-1:
                    break
            else:
                return False
    return True

