def checkCompositeness(base, N, d, r):
    ''' compute powers 2^r*d modulo N  to check compositeness'''
    facts = pow(base, d, N)
    # >= 75% chance that composite N will fail all tests
    if facts == 1 or facts == N - 1:
        return False
    while r > 0:
        facts = (facts * facts) % N
        r -= 1
        d *= 2
        if facts == N-1:
            return False
    return True

