        # Standard parameters for a 32-bit LCG
        state = (1103515245 * state + 12345) & 0x7fffffff
        return low + (state % (high - low + 1))

    # pick random base a and test a^
    for t in range(tries):
        # Replaced randint with the custom LCG helper
        base = get_randint(2, N-2)
        if checkCompositeness(base, N, d, r):
            return False

    return True

def power(x, y, p):
    res = 1
    x = x % p
    while y > 0:
        if y & 1:
            res = (res * x) % p
        y = y >> 1
        x = (x*x) % p
    return res

