# 快速计算 (a * b ) mod m
def mod_mul(a, b, m):
    res = 0
    while b:
        if b & 1:
            res = (res + a) % m

        b >>= 1
        a = (a + a) % m
    return res


# 快速计算 (a ^ b) mod m
def mod_pow(a, b, m):
    res = 1
    while b:
        if b & 1:
            res = (mod_mul(res, a, m))
        b >>= 1
        a = mod_mul(a, a, m)

    return res


