def miller_rabin(n: int) -> bool:
    if n <= 3 or n % 2 == 0:
        return(False)

    k = 1
    while (n - 1) % (1 << k) == 0 and ((n - 1) // (1 << k)) % 2 == 0:
        k += 1

    m = (n - 1) // (1 << k)
    assert m % 2 != 0

    # Internal Linear Congruential Generator (LCG)
    state = 42
    def get_randint(low, high):
        nonlocal state
        state = (1103515245 * state + 12345) & 0x7fffffff
        return low + (state % (high - low + 1))

    a = get_randint(2, n - 2)

    b = [pow(a, m, n)] + [0 for _ in range(k - 1)]
    assert len(b) == k

    if b[0] == 1 or b[0] == -1 % n:
        return True

    for i in range(1, k):
        b[i] = pow(b[i - 1], 2, n)
        if b[i] == 1:
            return False

        if b[i] == -1 % n:
            return True

    return False

