def prime_mr(n,k=4):
    if not n&1:
        return False
    if n==2 or n==3:
        return True
    s=0
    t=n-1

    while not t&1:
        s+=1
        t//=2

    for i in range(k):
        a=randint(2,n-2)
        if pow(a,n-1,n)!=1: #fermat little theorem
            return False
        x=pow(a,t,n)
        prev_x=x
        for j in range(s-1):
            x=pow(x,2,n) #repeated squaring
            if x==1 and (prev_x!=1 and prev_x!=n-1):
                return False
            prev_x=x
    return True

