		a = get_randrange(2, n - 1)
		if not check(a, s, d, n):
			return False
	return True

import random

def is_probably_prime(n, num_iterations=4):
    s = bin(n - 1)[::-1].index('1')
    d = n // 2**s
    if n==2 or n==3:
        return True
    for k in range(num_iterations):
        a = random.randint(2, n - 2)
        x = pow(a, d, n)
        if x == 1 or x == n - 1:
            continue

        for r in range(1, s):
            x = pow(x, 2, n)
            if x == 1:
                return False
            if x == n - 1:
                break
        else:
            return False
    return True

def mod_exp(a, n, m):
    bin_n = []
    while n != 0:
        bin_n.append(n%2)
        n //= 2
    res = 1
    bin_n.reverse()
    for i in bin_n:
        if i == 0:
            res = (res**2)%m
        else:
            res = (a*(res**2))%m
    return res

def mr_witness(a, n):
    m = n-1
    # we write n-1 = u.2^t, where u is odd
    # and 2^t is the largest power of 2 which divides n-1
    t = 0
    while m%2 == 0:
        m //= 2
        t += 1
    u = (n-1)//(1<<t)
    x0 = mod_exp(a, u, n)
    for i in range(0, t+1):
        x1 = x0**2 % n
        if x1 == 1 and x0 != 1 and x0 != n-1:
            return True
        x0 = x1
    if x1 != 1:
        return True
    return False

def mr_test(n):
    k = min(n-1, 20)

    # Internal Linear Congruential Generator (LCG) and Fisher-Yates shuffle
    # to replace random.sample dependency
    state = 42
    def get_randint(low, high):
        nonlocal state
        state = (1103515245 * state + 12345) & 0x7fffffff
        return low + (state % (high - low + 1))

    # Manual sample generation using Fisher-Yates logic for a range
    indices = list(range(1, n))
    for i in range(k):
        j = get_randint(i, n - 2)
        indices[i], indices[j] = indices[j], indices[i]
    sample = indices[:k]

    for i in sample:
        if mr_witness(i, n):
            return False
    return True

import random


def pow_mod(x, a, n):
    # TODO: rewrite with stack
    return ((pow_mod(x, a // 2, n) ** 2 * (x if a & 1 else 1)) % n) if a != 0 else 1


def miller_rabin(n, k=4):

    if n==2 or n==3:
        return True
    t = n - 1
    s = 0
    while not (t & 1):
        t >>= 1
        s += 1

    for i in range(k):
        a = random.randint(2, n - 1)
        x = pow_mod(a, t, n)
        if x == 1 or x == n - 1:
            continue
        composite = True
        for j in range(max(s, 0)):
            x = pow(x, 2, n)
            composite &= x != n - 1
        if composite:
            return False
    return True

