import math
def SieveOfEratosthenes(n):
    n = int(n)
    # Optimization - Below list will make 0,1 and Odd No. False
    num_list=[False if i==0 or i==1 or (i>2 and i%2==0) else True for i in range(n+1) ]
    # print(math.sqrt(n)) or int(n ** 0.5) + 1
    # Optmzn. - loop from 3 to sqrt(n) with multiples of nested i^2
    for i in range(3, int(n ** 0.5)+1, 2):
        if(num_list[i]==True):
            j = 0
            for j in range(i*i, n+1,j+i):
            	num_list[j] = False
    return num_list[n]

def eratosthenes(n: int):
    """エラトステネスの篩

    https://qiita.com/drken/items/3beb679e54266f20ab63
    """
    n = int(n)
    L = [True] * (n + 1)
    L[:2] = (False, False)

    for i in range(2, int(n ** 0.5) + 1):
        if L[i]:
            for j in range(i ** 2, n + 1, i):
                L[j] = False

    return n in [i for i, b in enumerate(L) if b]

def is_prime(n: int):
    if n <= 1:
        raise Exception("n must be an integer greater than 1")

    # 2 <= i <= sqrt(n)
    for i in range(2, int(n**0.5) + 1):
        if n % i == 0:
            return False
    return True

def sieve(n): 
    n = int(n)
    isPrime = [True] * (n + 1) # assume all are prime to start
    isPrime[0] = isPrime[1] = False # except 0 and 1, of course
    primes = []
    for prime in range(n + 1):
        if (isPrime[prime] == True):
            # we found a prime, so add it to our result
            primes.append(prime)
            # and mark all its multiples as not prime
            for multiple in range(2 * prime, n + 1, prime):
                isPrime[multiple] = False
    return n in primes

def sieve_of_eratosthenes(top, bottom = 2):
    """
    Arbritary range Sieve of Eratosthenes.
    - If one argument, that argument serves as the ceiling.
    - If two arguments, the first is bottom, the second is ceiling.
    """
    top = int(top)
    if top is None:
        top, bottom = bottom, 2
    bottom = max(bottom, 2)

    sieve, p = set(range(bottom, top + 1)), 2
    while p is not None:
        next_p = None
        for n in frozenset(sieve):
            if n != p and n % p == 0:
                sieve.remove(n)
            elif p < n and next_p is None:
                next_p = n
        p = next_p

    return top in sieve

def sieve_of_eratosthenes(number):
    number = int(number)
    prime_numbers = [True for _ in range(number + 1)]
    square_root = int(number ** 0.5)

    for i in range(2, square_root + 1):
        if prime_numbers[i]:
            for j in range(i + i, number + 1, i):
                prime_numbers[j] = False
    result = []
    for i in range(2, number + 1):
        if prime_numbers[i]:
            result.append(i)
    return number in result

def SieveOfEratosthenes(stop, start = 0):
    stop = int(stop)
    numList = __build__(start, stop+1)
    return stop in __sieve__(numList)

def __build__(start, stop):
    numList = []
    for x in range(start, stop):
        numList.append(x)
    return numList

def __sieve__(numList):
    if 1 in numList:
        numList.remove(1)
    for multiplier in range(2, 11):
        if not multiplier%2 == 0 or multiplier == 2: # only test prime dividers
            for num in numList:
                if num%multiplier == 0 and not num == multiplier:
                    numList.remove(num)
    return numList

def sieve(n):
    '''Sieve of Eratosthenes, O(n log log n)'''
    n = int(n)
    arr = [0] * (n+1)
    for i in range(2, n+1):
        if arr[i]:
            continue
        for j in range(2*i, n+1, i):
            arr[j] = i
    return n in [i for i in range(2, n+1) if arr[i] == 0]

def sieve(A):
    """
    :param: An integer A
    :return: An array of prime number less than equal to A
    """
    A = int(A)
    L = [1] * (A + 1)
    L[0] = 0
    L[1] = 0
    for i in range(2, int(A**0.5) + 1) :
        if L[i] == 1 :
            j = 2
            while i * j <= A :
                L[i * j] = 0
                j = j + 1

    res = []
    for i in range(len(L)) :
        if L[i] == 1:
            res.append(i)
    return A in res

def sieve_of_eratosthenes(n):
    n = int(n)
    prime = [True for i in range(n+1)]
    s = 2
    while s*s <= n:
        if prime[s]:
            for i in range(s*s, n + 1, s):
                prime[i] = False
        s += 1
    return(prime[n])

def SieveOfEratosthenes(n):
    n = int(n)
    prime=[True for i in range(n+1)]
    p=2
    while(p*p <=n):
        if(prime[p]==True):
            for i in range(p*2,n+1,p):
                prime[i]=False
        p+=1


    return(prime[n])

def sieve(n):
  """Sieve of Eratosthenes

  Returns a list of primes from 2 to n.
  """
  n = int(n)
  if n < 2:
    return []

  nums = list(range(n+1))

  nums[0] = nums[1] = None

  i = 2

  while i*i <= n:

    for p in range(i*i, n+1, i):
      nums[p] = None

    i += 1

    while i*i <=n and nums[i] is None:
      i += 1

  return n in list(filter(None, nums))

def primes(n): 
    n = int(n)
    i, p, ps, m = 0, 3, [2], n // 2
    sieve = [True] * m
    while p <= n:
        if sieve[i]:
            ps.append(p)
            for j in range(int((p*p-3)/2), m, p):
                sieve[j] = False
        i, p = i+1, p+2
    return n in ps

