def binary_search_iterative(arr, val):
    '''
    Binary search - iterative version
    Time complexity for search: O(log(n))
    Space complexity for search: O(1)
    '''
    low = 0; high = len(arr) - 1
    while low <= high:
        mid = int((low + high) / 2) 
        if arr[mid] == val:
            return mid
        elif arr[mid] < val:
            low = mid + 1
        else:
            high = mid - 1
    return -1

def search(number_list, n): 

    maxi = len(number_list) 
    mini = 0 

    pin = len(number_list) // 2 
    if number_list[mini]==n:
        return mini
    while maxi - mini != 1:
        # print "Pin: %d, Min: %d, Max: %d" % (pin, mini, maxi)
        if number_list[pin] == n:
            return pin

        elif number_list[pin] < n:
            # look on the right
            mini = pin 

        elif number_list[pin] > n:
            # look on the left
            maxi = pin 


        pin = ((maxi - mini) // 2) + mini

    return -1

def binary_search(a, v):
    s = 0
    e = len(a) - 1
    mid = (s+e)//2

    while s <= e:
        if a[mid] == v:
            return mid
        elif a[mid] < v:
            s = mid + 1
            mid = (s+e)//2
        elif a[mid] > v:
            e = mid - 1
            mid = (s+e)//2

    return -1

def bin_search(list, k):
  mid = len(list) // 2
  i = 0
  j = len(list) - 1
  while (i <= j):
    if (list[mid] == k):
      return mid
    elif (list[mid] < k):
      i = mid + 1
    elif (list[mid] > k):
      j = mid-1
    mid = i + (j - i) // 2
  return -1

def binary_search(alist, key):
    start = 0
    end = len(alist)
    while start < end:
        mid = (start + end)//2
        if alist[mid] > key:
            end = mid
        elif alist[mid] < key:
            start = mid + 1
        else:
            return mid
    return -1

def binary_search(sort_array, n):
    left = 0
    right = len(sort_array) - 1
    while left <= right:
        mid = (left + right) // 2
        if n == sort_array[mid]:
            return mid
        if sort_array[mid] < n:
            left = mid + 1
        else:
            right = mid - 1
    return -1

def binary_search(list, item):
    low = 0
    high = len(list) - 1

    while (low <= high):
        mid = int((low + high) / 2)
        guess = list[mid]
        if guess == item:
            return mid
        if guess > item:
            high = mid - 1
        elif guess < item:
            low = mid + 1

    return -1

def binary_search_recursive(elements, target, start=0, end=None):
    if end is None:
        end = len(elements) - 1
    if start > end:
        return -1

    midpoint = (start + end) // 2
    if target == elements[midpoint]:
        return midpoint

    if target < elements[midpoint]:
        return binary_search_recursive(elements, target, start, midpoint - 1)
    # target > elements[midpoint]
    return binary_search_recursive(elements, target, midpoint + 1, end)

def binary_search(a, num):
    min_idx = 0
    max_idx = len(a) - 1
    while min_idx <= max_idx:
        mid_idx = (min_idx + max_idx) // 2
        curr = a[mid_idx]
        if curr == num:
            return mid_idx

        if curr > num:
            max_idx = mid_idx - 1
        else:
            min_idx = mid_idx + 1

    return -1

def binarySearch(arr, num):
    arr = sorted(arr)
    start_index = 0
    end_index = len(arr) -1

    while start_index <= end_index:
        mid = start_index + (end_index - start_index) // 2
        mid_val = arr[mid]

        if mid_val == num:
            return mid
        elif num < mid_val:
            end_index = mid - 1
        else:
            start_index = mid + 1
    return -1

def binary_search(list, key):
    """Returns the position of key in the list if found, -1 otherwise.
    List must be sorted.
    """
    left = 0
    right = len(list) - 1
    while left <= right:
        middle = (left + right) // 2

        if list[middle] == key:
            return middle
        if list[middle] > key:
            right = middle - 1
        if list[middle] < key:
            left = middle + 1
    return -1

def binary_search(sequence, item):
# We want to find the middle position
    begin_i = 0
    end_i = len(sequence) - 1
# Where comparing the value to the value where searching for
    while begin_i <= end_i:
        midpoint = begin_i + (end_i - begin_i) // 2
        midpoint_value = sequence[midpoint]
        if midpoint_value == item:
            return midpoint

        elif item < midpoint_value:
            end_i = midpoint - 1

        else:
            begin_i = midpoint + 1

    return -1

def binary_search(seq, t):
    min = 0
    max = len(seq) - 1
    while True:
        if max < min:
            return -1
        m = min + (max - min) // 2
        if seq[m] < t:
            min = m + 1
        elif seq[m] > t:
            max = m - 1
        else:
            return m

def searchLocation(items,searchItem):
    start = 0
    end = len(items)
    if end < 0:
        return None
    while start <= end:
        niddle = (start+end)//2
        match = items[niddle]
        if searchItem == match:
            return niddle
        elif match > searchItem:
            end = niddle-1
        else:
            start = niddle+1

    return -1

def binarySearch(a_list, item):
    first = 0
    last = len(a_list)-1
    found = False

    while first<=last and not found:
        midpoint = (first+last)//2
        if a_list[midpoint] == item:
            # found = True
            return midpoint
        else:
            if item < a_list[midpoint]:
                last = midpoint-1
            else:
                first = midpoint+1
    # return found
    print (-1)

def binarySearch(arr,what):
    li = 0
    ls = len(arr)-1
    while li<=ls:
          middle = (li+ls)//2
          if(what == arr[middle]):
             return middle
          elif what > arr[middle]:
             li = middle + 1
          else:
             ls = middle - 1    
    return -1

def binarySearch(A, x):
    n = len(A)
    p = 0
    r = n - 1
    while p <= r:
        q = (p + r) // 2
        if A[q] == x:
            return q
        elif A[q] > x:
            r = q - 1
        else:	# A[q] < x
            p = q + 1

    return -1

import math

def binary_search(array, search):
    m = 0
    i = 0
    z = len(array) - 1
    while i<= z:
        m = math.floor(i + ((z - i) / 2))
        if array[m] == search:
            return m
        elif array[m] < search:
            i = m + 1
        elif array[m] > search:
            z = m - 1
    return -1

def binary_search(search_list, val):
  low = 0
  high = len(search_list) - 1

  while low <= high:
    mid = int(low + ((high - low)/2))
    if val == search_list[mid]:
        return mid

    if val < search_list[mid]:
        high = mid - 1
    else:
        low = mid + 1
  return -1

def binary_search(l, value):
    start_index = 0
    end_index = len(l) - 1

    while(start_index <= end_index):

        m = (start_index + end_index) // 2
        if l[m] < value:
            start_index = m + 1
        else:
            end_index = m - 1

    if start_index == len(l) or l[start_index] != value:
        return -1
    else:
        return start_index

import math
def binary_search_iterative(a, x):
    left = 0; right = len(a)
    while (left <= right):
        mid = math.floor((right - left) / 2) + left
        if (a[mid] == x):
            return mid
        elif (a[mid] > x):
            right = mid - 1
        elif (a[mid] < x):
            left = mid + 1
    return -1

def binary_search(array, key, left=0, right=None):
    if right is None:
        right = len(array) - 1
    if left > right:
        return -1

    mid = (left + right) // 2

    if key == array[mid]:
        return mid
    elif key < array[mid]:
        return binary_search(array, key, left, mid - 1)

    return binary_search(array, key, mid + 1, right)

def binary_search(arr, target):
    left, right = 0, len(arr) - 1
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1
    return -1  # Element not found

def binary_search(table, item):
    low = 0
    high = len(table) - 1
    while low <= high:
        mid = (low + high) // 2
        guess = table[mid]
        if guess < item:
            low = mid+1
        elif guess > item:
            high = mid-1
        elif guess == item:
            return mid
    return -1

def binary_search_basic(arr, target):
    low, high = 0, len(arr)
    while low < high:
        mid = (low+high) // 2 # low + (high-low)//2 if cares about overflow
        if target < arr[mid]:
            high = mid
        elif target > arr[mid]:
            low = mid + 1
        else:
            return mid
    return -1

def binary_search(arr, target):
    low = 0
    high = len(arr) - 1 # it starts with index 0

    while low <= high:
        mid = (low + high) // 2 # it represents the index of the middle element

        if arr[mid] < target:
            low = mid + 1
        else:
            high = mid - 1

    result = low != len(arr) and arr[low] == target
    return -1 if not result else low

def search(nums, target) -> int:        
        left = 0
        right = len(nums) - 1
        while left < right:
            midpoint = (left+right)//2
            if nums[midpoint] == target:
                return midpoint
            elif nums[midpoint] > target:
                right = midpoint - 1
            elif nums[midpoint] < target:
                left = midpoint + 1
        if nums[left] != target:
            return -1
        else:
            return left

def binary_search(array, x, low=0, high=None):
	high = high if high is not None else len(array)
	while low < high:
		mid = low + (high - low) // 2
		midval = array[mid]
		if midval < x:
			low = mid + 1
		elif midval > x:
			high = mid
		else:
			return mid
	return -1

def binarySearch(A, x):
	n = len(A)
	beg = 0
	end = n - 1
	result = -1
	while (beg <= end):
		mid = (beg + end) // 2
		if (A[mid] == x):
			return(mid)
		if (A[mid] < x):
			beg = mid + 1
			result = mid
		else:
			end = mid - 1
	return -1

def binary_search(a_list,target):
    min = 0
    max  = len(a_list) - 1
    while True:
        if max < min:
            return -1
        mid = (min + max) // 2
        if a_list[mid] < target:
            min = mid + 1
        elif target < a_list[mid]:
            max = mid - 1
        else:
            return mid

def binary_search_iterative(elements, target):
    start = 0
    end = len(elements) - 1

    while start <= end:
        #  // indicates floor division
        midpoint = (start + end) // 2
        if elements[midpoint] == target:
            return midpoint
        elif target < elements[midpoint]:
            end = midpoint - 1
        else:
            start = midpoint + 1

    return -1

def binary_search(arr_list, target):
    left, right = 0, len(arr_list) - 1
    while left <= right:
        mid = (left + right) // 2
        if arr_list[mid] == target:
            return mid
        elif arr_list[mid] < target:
            left = mid + 1
        else:
            right = mid - 1
    return -1

def binary_search(arr, target):
    left = 0
    right = len(arr) - 1

    while left <= right:
        mid = left + (right - left) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1

    return -1

def binarySearch(arr, target):
  l, r = 0, len(arr)-1
  while l + 1 < r:
    mid = l + (r - l) // 2
    if arr[mid] == target:
      return mid
    if arr[mid] < target:
      l = mid
    else:
      r = mid

  if arr[l] == target:
    return l
  if arr[r] == target:
    return r
  return -1

def binary_search(array, x, lo=0, hi=None):
	hi = hi if hi is not None else len(array)
	while lo < hi:
		mid = lo + (hi - lo) // 2
		midval = array[mid]
		if midval < x:
			lo = mid + 1
		elif midval > x:
			hi = mid
		else:
			return mid
	return -1

def binary_search(arr: list[int], target: int) -> int:
    left, right = 0, len(arr) - 1
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid  # could also return True
        if arr[mid] < target:
            left = mid + 1
        else:
            right = mid - 1
    return -1  # could also return False

from math import sqrt, trunc
def jump_search(array, key):
    size = len(array)
    block_size = sqrt(size)

    index = 0
    while array[trunc(min(block_size, size) - 1)] < key:
        index = block_size
        block_size += sqrt(size)

        if index >= size:
            return -1

    while array[trunc(index)] < key:
        index += 1

        if index == min(block_size, size):
            return -1

    if array[int(index)] == key:
        return trunc(index)

    return -1

def jump_search(arr, target):
    n = len(arr)
    step = int(n**0.5)
    prev = 0

    while arr[min(step, n)-1] < target:
        prev = step
        step += int(n**0.5)
        if prev >= n:
            return -1

    while arr[prev] < target:
        prev += 1

        if prev == min(step, n):
            return -1

    if arr[prev] == target:
        return prev

    return -1
